// ==================================================================
var URI = Java.type("java.net.URI");
var HttpClient = Java.type("java.net.http.HttpClient");
var HttpRequest = Java.type("java.net.http.HttpRequest");
var HttpResponse = Java.type("java.net.http.HttpResponse");
var Duration = Java.type("java.time.Duration");
var JavaDate = Java.type("java.util.Date");
var SimpleDateFormat = Java.type("java.text.SimpleDateFormat");
// ==================================================================

// 現在時刻を取得（yyyyMMddHHmm形式）
var dateFormat = new SimpleDateFormat("yyyyMMddHHmm");
dateFormat.setTimeZone(java.util.TimeZone.getTimeZone("Asia/Tokyo"));
var dateStr = dateFormat.format(new JavaDate());

var year  = parseInt(dateStr.substring(0, 4), 10);
var month = parseInt(dateStr.substring(4, 6), 10);
var day   = parseInt(dateStr.substring(6, 8), 10);

$runner.getLogger().info("[calcBusinessDay] current datetime: " + dateStr);

// 祝日APIから当年・翌年分を取得（年をまたぐケースに対応）
var holidays = {};

try {
    var client = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(10))
        .build();

    // 当年・翌年の2年分を取得してマージ
    var years = [year, year + 1];
    for (var i = 0; i < years.length; i++) {
        var apiUrl = "https://holidays-jp.github.io/api/v1/" + years[i] + "/date.json";

        var request = HttpRequest.newBuilder()
            .uri(URI.create(apiUrl))
            .header("Accept", "application/json")
            .timeout(Duration.ofSeconds(10))
            .GET()
            .build();

        var response = client.send(request, HttpResponse.BodyHandlers.ofString());

        if (response.statusCode() === 200) {
            var yearHolidays = JSON.parse(response.body());
            for (var key in yearHolidays) {
                holidays[key] = yearHolidays[key];
            }
        } else {
            $runner.getLogger().warn("[calcBusinessDay] API response: " + response.statusCode() + " for year: " + years[i]);
        }
    }

} catch (e) {
    $runner.getLogger().error("[calcBusinessDay] Holiday API error: " + e.message);
}

// 指定日が営業日（土日祝以外）かどうかを判定する関数
var isBusinessDay = function(cal) {
    var dow = cal.get(java.util.Calendar.DAY_OF_WEEK);
    if (dow === java.util.Calendar.SUNDAY || dow === java.util.Calendar.SATURDAY) {
        return false;
    }
    var y = cal.get(java.util.Calendar.YEAR);
    var m = cal.get(java.util.Calendar.MONTH) + 1;
    var d = cal.get(java.util.Calendar.DATE);
    var mm = (m < 10 ? "0" : "") + m;
    var dd = (d < 10 ? "0" : "") + d;
    var key = y + "-" + mm + "-" + dd;
    if (holidays[key] !== undefined) {
        return false;
    }
    return true;
};

// 今日を起点に3営業日後を計算
var cal = java.util.Calendar.getInstance(
    java.util.TimeZone.getTimeZone("Asia/Tokyo")
);
cal.set(year, month - 1, day, 0, 0, 0);
cal.set(java.util.Calendar.MILLISECOND, 0);

var count = 0;
while (count < 3) {
    cal.add(java.util.Calendar.DATE, 1);
    if (isBusinessDay(cal)) {
        count++;
    }
}

// 結果を "m月d日" 形式で取得
var resultMonth = cal.get(java.util.Calendar.MONTH) + 1;
var resultDay   = cal.get(java.util.Calendar.DATE);
var result = resultMonth + "月" + resultDay + "日";

$runner.getLogger().info("[calcBusinessDay] 3 business days later: " + result);

$runner.setResult(result);

// ==================================================================
var JavaDate = Java.type("java.util.Date");
var SimpleDateFormat = Java.type("java.text.SimpleDateFormat");
// ==================================================================

// 現在日付を取得（Asia/Tokyo）
var dateFormat = new SimpleDateFormat("yyyyMMdd");
dateFormat.setTimeZone(java.util.TimeZone.getTimeZone("Asia/Tokyo"));
var todayStr = dateFormat.format(new JavaDate());

var todayYear  = parseInt(todayStr.substring(0, 4), 10);
var todayMonth = parseInt(todayStr.substring(4, 6), 10);
var todayDay   = parseInt(todayStr.substring(6, 8), 10);

$runner.getLogger().info("[checkReservationDate] today: " + todayStr);

// 当日・明日・明後日のCalendarオブジェクトを生成
var tz = java.util.TimeZone.getTimeZone("Asia/Tokyo");

var calToday = java.util.Calendar.getInstance(tz);
calToday.set(todayYear, todayMonth - 1, todayDay, 0, 0, 0);
calToday.set(java.util.Calendar.MILLISECOND, 0);

var calTomorrow = java.util.Calendar.getInstance(tz);
calTomorrow.set(todayYear, todayMonth - 1, todayDay, 0, 0, 0);
calTomorrow.set(java.util.Calendar.MILLISECOND, 0);
calTomorrow.add(java.util.Calendar.DATE, 1);

var calDayAfter = java.util.Calendar.getInstance(tz);
calDayAfter.set(todayYear, todayMonth - 1, todayDay, 0, 0, 0);
calDayAfter.set(java.util.Calendar.MILLISECOND, 0);
calDayAfter.add(java.util.Calendar.DATE, 2);

// 比較用に "yyyyMMdd" 数値へ変換するヘルパー
var calToInt = function(cal) {
    var y = cal.get(java.util.Calendar.YEAR);
    var m = cal.get(java.util.Calendar.MONTH) + 1;
    var d = cal.get(java.util.Calendar.DATE);
    return y * 10000 + m * 100 + d;
};

var todayInt     = calToInt(calToday);
var tomorrowInt  = calToInt(calTomorrow);
var dayAfterInt  = calToInt(calDayAfter);

$runner.getLogger().info(
    "[checkReservationDate] today=" + todayInt +
    " tomorrow=" + tomorrowInt +
    " dayAfter=" + dayAfterInt
);

// モジュール「openAI_現在の予約日」の出力値を取得（yyyy-MM-dd 00:00:00形式）
var reservationRaw = $runner.getModuleResult("openAI_現在の予約日");

$runner.getLogger().info("[checkReservationDate] reservationRaw: " + reservationRaw);

// yyyy-MM-dd 00:00:00 → yyyyMMdd の数値に変換
// 例: "2025-04-14 00:00:00" → 20250414
var result;

if (!reservationRaw || reservationRaw.trim() === "") {
    $runner.getLogger().warn("[checkReservationDate] reservationRaw is empty");
    result = "success";

} else {
    var parts = reservationRaw.trim().split(" ");        // ["2025-04-14", "00:00:00"]
    var dateParts = parts[0].split("-");                 // ["2025", "04", "14"]
    var reservationInt = parseInt(dateParts[0], 10) * 10000
                       + parseInt(dateParts[1], 10) * 100
                       + parseInt(dateParts[2], 10);     // 20250414

    $runner.getLogger().info("[checkReservationDate] reservationInt: " + reservationInt);

    if (reservationInt === todayInt ||
        reservationInt === tomorrowInt ||
        reservationInt === dayAfterInt) {
        result = "代表案内";
    } else {
        result = "success";
    }
}

$runner.getLogger().info("[checkReservationDate] => " + result);

$runner.setResult(result);

